class Solution {
    public double new21Game(int n, int k, int maxPts) {
        if (k == 0 || n - k + 1 >= maxPts) return 1.0;
        double dp[] = new double[n + 1];
        dp[0] = 1.0;
        double s = 1.0, ans = 0.0;
        for (int i = 1; i <= n; i++) {
            dp[i] = s / maxPts;
            if (i <= k) s += dp[i];
            if (i - maxPts - 1 >= 0) s -= dp[i - maxPts - 1];
            if (i >= k) ans += dp[i];
        }
        return ans;
    }
}
